function toISO(v) {
  if (v == null || v === '') return null;
  if (typeof v === 'number') {
    return new Date(Math.round((v - 25569) * 86400 * 1000)).toISOString().slice(0, 10);
  }
  return String(v);
}
const out = [];
for (const item of $input.all()) {
  const j = item.json;
