const taxonomy = {
  'integrations': 'Integrations', 'api': 'Integrations', 'salesforce': 'Integrations',
  'hubspot': 'Integrations', 'integration outage': 'Integrations',
  'analytics': 'Analytics & Reporting', 'reporting': 'Analytics & Reporting', 'analytics gap': 'Analytics & Reporting',
  'latency': 'Latency & Performance', 'latency degradation': 'Latency & Performance',
  'knowledge_base': 'Knowledge Base / RAG', 'kb': 'Knowledge Base / RAG',
  'kb re-index latency': 'Knowledge Base / RAG', 'knowledge base': 'Knowledge Base / RAG',
  'voice_quality': 'Voice Quality & Multilingual', 'voice': 'Voice Quality & Multilingual',
  'voice quality': 'Voice Quality & Multilingual', 'multilingual': 'Voice Quality & Multilingual',
  'german tts': 'Voice Quality & Multilingual', 'multilingual switching': 'Voice Quality & Multilingual',
  'language': 'Voice Quality & Multilingual',
  'reliability': 'Reliability / Trust', 'hallucination incident': 'Reliability / Trust',
  'prompt reliability': 'Reliability / Trust',
  'sso': 'Identity & Compliance', 'compliance': 'Identity & Compliance',
  'sso blocker': 'Identity & Compliance', 'sso/security': 'Identity & Compliance',
  'hipaa delay': 'Identity & Compliance',
  'transfer': 'Telephony & Transfer', 'call-transfer': 'Telephony & Transfer',
  'telephony': 'Telephony & Transfer', 'warm transfer': 'Telephony & Transfer',
  'concurrency limits': 'Telephony & Transfer',
  'pricing': 'Pricing & Billing', 'billing': 'Pricing & Billing', 'billing dispute': 'Pricing & Billing',
  'onboarding': 'Onboarding & Activation', 'onboarding speed': 'Onboarding & Activation'
};

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const key = (j.raw_tag || '').toString().trim().toLowerCase();
  const parent_theme = taxonomy[key] || '';
  out.push({ json: { ...j, parent_theme, match_method: parent_theme ? 'deterministic' : '' } });
}
return out;

const items = $input.all();
const records = items.map(i => ({ record_id: i.json.record_id, raw_tag: i.json.raw_tag, raw_text: i.json.raw_text }));

const chunkSize = 50;
const chunks = [];
for (let i = 0; i < records.length; i += chunkSize) {
  chunks.push(records.slice(i, i + chunkSize));
}
return chunks.map(chunk => ({ json: { records: chunk } }));

const originals = $('Unmatched Records').all();
const chunkResults = $input.all();

const byId = {};
for (const result of chunkResults) {
  const classifications = (result.json.output && result.json.output.classifications) || [];
  for (const c of classifications) byId[c.record_id] = c;
}

return originals.map(item => {
  const j = item.json;
  const c = byId[j.record_id] || {};
  return { json: { ...j, parent_theme: c.parent_theme || 'Unclassified/Other', match_method: 'ai_fallback', ai_confidence: c.confidence || 'low' } };
});

const items = $input.all();
const records = items.map(i => ({
  record_id: i.json.record_id,
  parent_theme: i.json.parent_theme || 'Unclassified/Other',
  text: (i.json.raw_title || '') + ' — ' + (i.json.raw_tag || '') + ': ' + (i.json.raw_text || '')
}));
return [{ json: { records } }];

const clusters = $json.valid_clusters || [];
const original = $('FR Records').all().map(i => i.json);
const byId = Object.fromEntries(original.map(r => [r.record_id, r]));

const dropIds = new Set();
const mergedFor = {};
for (const cluster of clusters) {
  const ids = cluster.record_ids;
  const canonical = ids[0];
  mergedFor[canonical] = { count: ids.length - 1, accounts: new Set(), arr: 0 };
  for (let i = 1; i < ids.length; i++) {
    dropIds.add(ids[i]);
    const dup = byId[ids[i]];
    if (!dup) continue;
    mergedFor[canonical].arr += Number(dup.fr_weighted_arr_usd) || 0;
    String(dup.linked_accounts || '').replace(/\u2026/g, '').split(',')
      .map(s => s.trim()).filter(Boolean)
      .forEach(a => mergedFor[canonical].accounts.add(a));
  }
}

const out = [];
for (const rec of original) {
  if (dropIds.has(rec.record_id)) continue;
  const m = mergedFor[rec.record_id];
  if (m) {
    const existing = String(rec.linked_accounts || '').replace(/\u2026/g, '').split(',').map(s => s.trim()).filter(Boolean);
    const union = Array.from(new Set([...existing, ...m.accounts]));
    out.push({ json: { ...rec,
      merged_duplicate_count: m.count,
      linked_accounts: union.join(', '),
      fr_weighted_arr_usd: (Number(rec.fr_weighted_arr_usd) || 0) + m.arr
    }});
  } else {
    out.push({ json: { ...rec, merged_duplicate_count: 0 } });
  }
}
return out;

const clusters = $json.valid_clusters || [];
const original = $('FR Records').all().map(i => i.json);

const statusMap = {};
for (const cluster of clusters) {
  const ids = cluster.record_ids;
  const canonical = ids[0];
  for (let i = 0; i < ids.length; i++) {
    statusMap[ids[i]] = i === 0 ? 'Unique (canonical)' : ('Duplicate of ' + canonical);
  }
}

return original.map(rec => ({
  json: { FR_ID: rec.record_id, Duplicate_Status: statusMap[rec.record_id] || 'Unique' }
}));

return $input.all().map(item => {
  const j = { ...item.json };
  delete j.output;
  return { json: {
    ...j,
    ai_confidence: j.ai_confidence !== undefined ? j.ai_confidence : null,
    merged_duplicate_count: j.merged_duplicate_count !== undefined ? j.merged_duplicate_count : 0
  }};
});

const accounts = $('Read Accounts').all().map(i => i.json);
const arrLookup = {};
for (const a of accounts) arrLookup[a.Account] = Number(a.ARR_USD) || 0;

const records = $('Fill Missing Fields').all();

return records.map(item => {
  const j = item.json;

  const account_arr_usd = j.account && arrLookup[j.account] !== undefined ? arrLookup[j.account] : 0;

  let sample_accounts_arr_usd = 0;
  let arr_sample_truncated = false;
  if (j.linked_accounts) {
    const names = String(j.linked_accounts).replace(/\u2026/g, '').split(',').map(s => s.trim()).filter(Boolean);
    for (const n of names) if (arrLookup[n] !== undefined) sample_accounts_arr_usd += arrLookup[n];
    arr_sample_truncated = (j.linked_accounts_count || 0) > names.length;
  }

  return { json: { ...j, account_arr_usd, sample_accounts_arr_usd, arr_sample_truncated } };
});

const input = $input.first().json.records;
const groups = {};

for (const r of input) {
  const theme = r.parent_theme || 'Unclassified/Other';
  if (!groups[theme]) groups[theme] = [];
  groups[theme].push({ record_id: r.record_id, text: r.text });
}

return Object.entries(groups).map(([theme, records]) => ({
  json: { parent_theme: theme, records }
}));

const items = $input.all();
const allClusters = [];

for (const item of items) {
  const clusters = (item.json.output && item.json.output.clusters) || [];
  for (const c of clusters) {
    allClusters.push({
      record_ids: c.record_ids || [],
      reason: c.reason || ''
    });
  }
}

return [{ json: { clusters: allClusters } }];

const clusters = $json.clusters || [];
const original = $('FR Records').all().map(i => i.json);
const byId = Object.fromEntries(original.map(r => [r.record_id, r]));

const valid_clusters = [];
const rejected_clusters = [];

for (const cluster of clusters) {
  const ids = (cluster.record_ids || []).filter(Boolean);
  const knownIds = ids.filter(id => byId[id]);
  const unknownIds = ids.filter(id => !byId[id]);

  if (knownIds.length < 2) {
    rejected_clusters.push({ ...cluster, reason_rejected: 'fewer than 2 valid record_ids', unknownIds });
    continue;
  }

  const themes = new Set(knownIds.map(id => byId[id].parent_theme));
  if (themes.size > 1) {
    rejected_clusters.push({ ...cluster, reason_rejected: 'members span multiple themes: ' + [...themes].join(', ') });
    continue;
  }

  if (!cluster.reason || !cluster.reason.trim()) {
    rejected_clusters.push({ ...cluster, reason_rejected: 'missing justification' });
    continue;
  }

  valid_clusters.push({ record_ids: knownIds, reason: cluster.reason });
}

return [{ json: { valid_clusters, rejected_clusters } }];
